const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
const required = ['advisor_id','license_type','license_number','jurisdiction','issued_date','expires_date'];
for (const f of required) { if (!body[f]) return { json: { _empty: true, status: 400, error: f + ' required' } }; }
return { json: { token: token, advisor_id: body.advisor_id, license_type: body.license_type, license_number: String(body.license_number), jurisdiction: body.jurisdiction, issued_date: body.issued_date, expires_date: body.expires_date, ce_hours_required: body.ce_hours_required || 30, ce_period_start: body.ce_period_start || body.issued_date, ce_period_end: body.ce_period_end || body.expires_date, documentation_url: body.documentation_url || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','mga_principal','admin'];
if (allowed.indexOf(row.user_role) < 0) return { json: { _unauthorized: true, status: 403, error: 'Role not permitted' } };
// Encrypt license number with AES-256-GCM. Key from env. Output base64 ciphertext + nonce + tag.
const crypto = require('crypto');
const keyB64 = process.env.LICENSE_ENCRYPTION_KEY || '';
let encrypted = '';
if (keyB64) {
  try {
    const key = Buffer.from(keyB64, 'base64');
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
    const c = Buffer.concat([cipher.update($('Extract Inputs').item.json.license_number, 'utf8'), cipher.final()]);
    const tag = cipher.getAuthTag();
    encrypted = Buffer.concat([iv, tag, c]).toString('base64');
  } catch (e) { encrypted = ''; }
}
if (!encrypted) {
  // Fallback: tag plaintext with marker so Mary knows to set the key. Phase 5b enforces.
  encrypted = 'PLAINTEXT_NO_KEY:' + Buffer.from($('Extract Inputs').item.json.license_number).toString('base64');
}
const i = $('Extract Inputs').item.json;
const last4 = String(i.license_number).slice(-4);
return { json: { _ok: true, verifier_id: row.id || row.user_id, advisor_id: i.advisor_id, license_type: i.license_type, license_number_encrypted: encrypted, license_number_last4: last4, jurisdiction: i.jurisdiction, issued_date: i.issued_date, expires_date: i.expires_date, ce_hours_required: i.ce_hours_required, ce_period_start: i.ce_period_start, ce_period_end: i.ce_period_end, documentation_url: i.documentation_url } };
